#include <stdio.h>
#include <stdlib.h>
#include <string.h>
int main(){
    int T;
    if(scanf("%d", &T)!=1) return 0;
    getchar(); // consume newline after T
    char line[1024];
    for(int t=0; t<T; ++t){
        if(!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = 0; // remove trailing newline
        char *token = strtok(line, " ");
        int first = 1;
        while(token){
            int x = atoi(token);
            int a = x < 0 ? -x : x;
            if(!first) printf(" ");
            printf("%d", a);
            first = 0;
            token = strtok(NULL, " ");
        }
        if(t < T-1) printf("\n");
    }
    return 0;
}

