import sys
def solve():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    T = int(data[0].strip())
    out_lines = []
    for i in range(1, T+1):
        if i >= len(data):
            line = ''
        else:
            line = data[i]
        nums = line.split()
        abs_vals = [str(abs(int(x))) for x in nums]
        out_lines.append(' '.join(abs_vals))
    sys.stdout.write('\n'.join(out_lines))
if __name__ == "__main__":
    solve()

